import "flatpickr/dist/flatpickr.min.css";
import "../styles/booking.css";
import { useNavigate } from "react-router-dom";

const API_BASE = process.env.REACT_APP_API_URL || "http://127.0.0.1:8000";

export default function Reservation() {
  const navigate = useNavigate();
  const token = localStorage.getItem("access_token");

  useEffect(() => {
    if (!token) {
      navigate("/login");
    }
  }, [token, navigate]);

  const [rooms, setRooms] = useState([]);
  const [reservedRanges, setReservedRanges] = useState([]);
  const [errorMsg, setErrorMsg] = useState("");
  const dateInputRef = useRef(null);
  const fpRef = useRef(null);

  const [selectedRoom, setSelectedRoom] = useState(null);
  const [roomDropdownOpen, setRoomDropdownOpen] = useState(false);
  const [adults, setAdults] = useState(1);
  const [numRooms, setNumRooms] = useState(1);
  const [form, setForm] = useState({
    reservation_dates: "",
    room_type: "",
    name: "",
    email: "",
    phone: "",
    message: "",
  });

  useEffect(() => {
    let mounted = true;

    async function loadData() {
      try {
        const rRes = await fetch(`${API_BASE}/api/rooms/`);
        const rJson = rRes.ok ? await rRes.json() : [];

        const roomsNormalized = Array.isArray(rJson)
          ? rJson.map((r) => ({
              room_id: r.id ?? r.room_id ?? "",
              room_name: r.room_name ?? r.name ?? `Room ${r.id ?? ""}`,
              price: r.price ?? r.rate ?? 0,
              image:
                r.image && typeof r.image === "string"
                  ? (r.image.startsWith("http") ? r.image : `${API_BASE}${r.image}`)
                  : "/assets/images/uploads/default.jpg",
              raw: r,
            }))
          : [];

        const rvRes = await fetch(`${API_BASE}/api/reservations/`);
        const rvJson = rvRes.ok ? await rvRes.json() : [];

        const ranges = Array.isArray(rvJson)
          ? rvJson
              .filter((it) =>
                it.status ? it.status.toLowerCase() !== "cancelled" : true
              )
              .map((it) => {
                const checkin = it.checkin ?? it.check_in ?? null;
                const checkout = it.checkout ?? it.check_out ?? null;
                if (!checkin || !checkout) return null;
                const toDate = new Date(checkout);
                toDate.setDate(toDate.getDate() - 1);
                return { from: checkin, to: toDate.toISOString().slice(0, 10) };
              })
              .filter(Boolean)
          : [];

        if (!mounted) return;
        setRooms(roomsNormalized);
        setReservedRanges(ranges);

        if (roomsNormalized.length > 0 && !selectedRoom) {
          setSelectedRoom(roomsNormalized[0]);
          setForm((f) => ({ ...f, room_type: roomsNormalized[0].room_name }));
        }
      } catch (err) {
        console.error("Failed to load rooms/reservations:", err);
        setErrorMsg("Failed to load data from server.");
      }
    }

    loadData();
    return () => {
      mounted = false;
    };
  }, []);

  useEffect(() => {
    const el = dateInputRef.current;
    if (!el) return;

    if (fpRef.current) fpRef.current.destroy();

    fpRef.current = flatpickr(el, {
      mode: "range",
      dateFormat: "Y-m-d",
      minDate: "today",
      disable: reservedRanges,
      onClose: (_, dateStr) =>
        setForm((f) => ({ ...f, reservation_dates: dateStr })),
    });

    return () => fpRef.current?.destroy();
  }, [reservedRanges]);

  const handleInput = (e) => {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMsg("");

    const dates = form.reservation_dates.split(" to ");
    const check_in = dates[0];
    const check_out = dates[1];

    if (!check_in || !check_out) {
      setErrorMsg("Please select check-in and check-out dates.");
      return;
    }

    try {
      const resp = await fetch(`${API_BASE}/api/reservations/`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          name: form.name,
          email: form.email,
          phone: form.phone,
          adults,
          children: 0,
          check_in,
          check_out,
          message: form.message,
        }),
      });

      if (!resp.ok) throw new Error("Booking failed");

      alert("Reservation successful!");
      navigate("/");
    } catch (err) {
      setErrorMsg(err.message);
    }
  };

  return (
    <div>
      {/* Navbar */}
      <nav className="nav">
        <div className="nav-inner">
          <div className="brand">
            <img src="/assets/glamp_logo.png" alt="Logo" className="logo" />
          </div>
          <div className="menu">
            <a href="/">Home</a>
            <a href="/menu">Menu</a>
            <a href="/reservation" className="active">Reservation</a>
            <a href="/login">Login</a>
            <a href="/register" className="reserve">Register</a>
          </div>
        </div>
      </nav>

      {/* Hero */}
      <section className="hero" style={{ background: 'linear-gradient(rgba(0,0,0,0.5), rgba(0,0,0,0.5)), url("/assets/images/reservation.jpg") center/cover' }}>
        <div className="hero-overlay">
          <h1>Book Your Stay</h1>
          <p>Experience luxury in nature at Eden's Glamp Resort</p>
        </div>
      </section>

      {/* Reservation Form */}
      <section className="reservation-section">
        <div className="reservation-container">
          <h2 style={{ textAlign: 'center', marginBottom: 30, color: '#222' }}>Make a Reservation</h2>
          
          {errorMsg && (
            <div style={{ background: '#ffebee', color: '#c62828', padding: 12, borderRadius: 6, marginBottom: 20 }}>
              {errorMsg}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            {/* Room Selection */}
            <div className="form-group">
              <label>Select Room</label>
              <div className="custom-select">
                <div
                  className="selected-room"
                  onClick={() => setRoomDropdownOpen(!roomDropdownOpen)}
                >
                  {selectedRoom && (
                    <>
                      <img src={selectedRoom.image} alt={selectedRoom.room_name} />
                      <div>
                        <h4>{selectedRoom.room_name}</h4>
                        <p>₹{selectedRoom.price} / night</p>
                      </div>
                    </>
                  )}
                  <i className={roomDropdownOpen ? "▲" : "▼"}></i>
                </div>
                <div className={`room-options ${roomDropdownOpen ? "show" : ""}`}>
                  {rooms.map((room) => (
                    <div
                      key={room.room_id}
                      className="room-card"
                      onClick={() => {
                        setSelectedRoom(room);
                        setForm((f) => ({ ...f, room_type: room.room_name }));
                        setRoomDropdownOpen(false);
                      }}
                    >
                      <img src={room.image} alt={room.room_name} />
                      <div>
                        <h4>{room.room_name}</h4>
                        <p>₹{room.price} / night</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Date Selection */}
            <div className="form-group">
              <label>Select Dates</label>
              <input
                ref={dateInputRef}
                type="text"
                placeholder="Select check-in and check-out dates"
                value={form.reservation_dates}
                readOnly
                style={{ cursor: 'pointer' }}
              />
            </div>

            {/* Guests Counter */}
            <div className="form-group">
              <div className="counters">
                <div className="counter">
                  <label>Adults</label>
                  <button type="button" onClick={() => setAdults(Math.max(1, adults - 1))}>-</button>
                  <span>{adults}</span>
                  <button type="button" onClick={() => setAdults(adults + 1)}>+</button>
                </div>
                <div className="counter">
                  <label>Rooms</label>
                  <button type="button" onClick={() => setNumRooms(Math.max(1, numRooms - 1))}>-</button>
                  <span>{numRooms}</span>
                  <button type="button" onClick={() => setNumRooms(numRooms + 1)}>+</button>
                </div>
              </div>
            </div>

            {/* Guest Details */}
            <div className="form-group">
              <div className="details-grid">
                <div className="left">
                  <input
                    type="text"
                    name="name"
                    placeholder="Your Name"
                    value={form.name}
                    onChange={handleInput}
                    required
                  />
                  <input
                    type="email"
                    name="email"
                    placeholder="Email Address"
                    value={form.email}
                    onChange={handleInput}
                    required
                  />
                  <input
                    type="tel"
                    name="phone"
                    placeholder="Phone Number"
                    value={form.phone}
                    onChange={handleInput}
                    required
                  />
                </div>
                <div className="right">
                  <textarea
                    name="message"
                    placeholder="Special Requests (optional)"
                    value={form.message}
                    onChange={handleInput}
                  ></textarea>
                </div>
              </div>
            </div>

            <div style={{ textAlign: 'center' }}>
              <button type="submit" className="check-btn">Confirm Reservation</button>
            </div>
          </form>
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <div className="footer-inner">
          <div className="footer-col">
            <div className="footer-logo">Eden's Glamp</div>
            <div className="stars">★★★★★</div>
            <p>Luxury in Nature</p>
          </div>
          <div className="footer-col">
            <h4>Contact</h4>
            <p>info@edensglamp.com</p>
            <p>+91 98765 43210</p>
          </div>
          <div className="footer-col">
            <h4>Follow Us</h4>
            <div className="socials">
              <a href="#">Instagram</a>
              <a href="#">Facebook</a>
              <a href="#">Twitter</a>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
}
